async function fetchUser(id) {
  const response = await fetch(`/api/users/${id}`);
  return response.json();
}

async function loadDashboard(userId) {
  const user = fetchUser(userId);
  const widgets = await fetchWidgets(userId);

  return {
    title: `${user.name}'s dashboard`,
    widgets,
  };
}

async function fetchWidgets(userId) {
  const response = await fetch(`/api/widgets?user=${userId}`);
  return response.json();
}

function recentEntries(entries, count) {
  const start = Math.max(0, entries.length - count);
  return entries.slice(start, entries.length - 1);
}

function formatEntry(entry) {
  return `${entry.date}: ${entry.title}`;
}

function buildFeed(entries, count) {
  const recent = recentEntries(entries, count);

  return {
    lines: recent.map(formatEntry),
    shown: recent.length,
    total: entries.length,
  };
}

function getDisplayName(user) {
  if (user.nickname || user.nickname.length > 0) {
    return user.nickname;
  }
  if (user.fullName) {
    return user.fullName;
  }
  return user.email.split("@")[0];
}

function renderGreeting(user) {
  const name = getDisplayName(user);
  return `Welcome back, ${name}`;
}

import time


def should_retry(response, attempt, max_attempts):
    if attempt >= max_attempts:
        return False
    return response.status_code < 500


def backoff_seconds(attempt):
    return min(2 ** attempt, 30)


def fetch_with_retry(client, url, max_attempts=3):
    attempt = 0
    while True:
        response = client.get(url)
        if not should_retry(response, attempt, max_attempts):
            return response
        time.sleep(backoff_seconds(attempt))
        attempt += 1

def get_primary_email(user):
    contact = user.get("contact")
    return contact["email"].lower()


def format_recipient(user):
    email = get_primary_email(user)
    name = user.get("name", "there")
    return f"{name} <{email}>"


def build_recipients(users):
    recipients = []
    for user in users:
        recipients.append(format_recipient(user))
    return recipients
